import { FilterSegment } from './filter-segment';
/**
 * Preset containing a configuration of one or more segments.
 *
 * The preset is identified by ID that's not stable in the long term.
 * It means, consumers can't rely on it to identify presets created during previous sessions.
 */
export interface SegmentsPreset {
    id: string;
    segments: FilterSegment[];
}
